3400	\begin{lemma}[Presheaf-side unit mate identity]
3401	  \label{lem:presheaf_unit_comp_map_eta}
3402	  \lean{AlgebraicGeometry.Scheme.Modules.presheafUnit_comp_map_eta}
3403	  \uses{lem:presheaf_pushforward_laxmonoidal, lem:presheaf_pullback_oplaxmonoidal}
3404	  At the presheaf level the pullback--pushforward adjunction unit at the monoidal unit,
3405	  post-composed with the pushforward of the oplax unit comparison, recovers the lax unit:
3406	  \[
3407	    \mathtt{presheafAdj}.\mathrm{unit}.\mathrm{app}\,\mathbf{1}^{\mathrm{p}}
3408	      \;\mathbin{;}\;
3409	      (\mathtt{pushforward}\,\varphi').\mathrm{map}\,(\eta\,F)
3410	      \;=\; \varepsilon(\mathtt{pushforward}\,\varphi'),
3411	  \]
3412	  where \(\mathtt{presheafAdj} = \mathtt{pullbackPushforwardAdjunction}\,\varphi'\) is the
3413	  presheaf pullback--pushforward adjunction and \(F = \mathtt{pullback}\,\varphi'\).
3414	\end{lemma}
3415	
3416	\begin{proof}
3417	  \uses{lem:presheaf_pushforward_laxmonoidal, lem:presheaf_pullback_oplaxmonoidal}
3418	  This is Mathlib's general adjunction-mate identity
3419	  \(\mathtt{Adjunction.unit\_app\_unit\_comp\_map\_}\eta\) instantiated at the presheaf
3420	  pullback--pushforward adjunction \(\mathtt{pullbackPushforwardAdjunction}\,\varphi'\). That
3421	  identity holds for any adjunction whose left adjoint is oplax monoidal and whose right adjoint
3422	  is lax monoidal in a mate-compatible way. The compatible pair is
3423	  \(\mathtt{presheafPushforwardLaxMonoidal}\)
3424	  (\cref{lem:presheaf_pushforward_laxmonoidal}) and \(\mathtt{presheafPullbackOplaxMonoidal}\)
3425	  (\cref{lem:presheaf_pullback_oplaxmonoidal}), so the
3426	  mate identity applies to the concrete adjunction and yields the stated equation.
3427	\end{proof}
